"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

// ===== 题目配置 =====
interface Choice {
  label: string;
  correct: boolean;
}

interface QuestionConfig {
  expression: string;
  prompt: string;
  choices: Choice[];
  explanation: string;
}

const QUESTIONS: QuestionConfig[] = [
  {
    expression: "60 ÷ 3",
    prompt: "口算一下，60 ÷ 3 等于多少？",
    choices: [
      { label: "20", correct: true },
      { label: "30", correct: false },
      { label: "15", correct: false },
      { label: "25", correct: false },
    ],
    explanation: "60 ÷ 3 = 20，整十数除以一位数，可以直接口算！",
  },
  {
    expression: "283 ÷ 3",
    prompt: "先估算一下，283 ÷ 3 大约是多少？",
    choices: [
      { label: "约 80", correct: false },
      { label: "约 90", correct: false },
      { label: "约 100", correct: false },
      { label: "约 95", correct: true },
    ],
    explanation: "283 ÷ 3 ≈ 94...1，接近 95！",
  },
];

// ===== SVG 条形图组件 =====
function ComparisonBarChart() {
  // 数据
  const items = [
    { label: "60 ÷ 3", value: 20, max: 100, color: "var(--primary)" },
    { label: "283 ÷ 3", value: 94, max: 100, color: "var(--accent)" },
  ];
  const barMaxWidth = 280;
  const barHeight = 36;
  const chartHeight = 200;

  return (
    <div className="mt-4 flex justify-center">
      <svg viewBox={`0 0 ${barMaxWidth + 120} ${chartHeight}`} className="w-full max-w-md">
        {/* 背景网格线 */}
        {[0, 25, 50, 75, 100].map((tick) => {
          const x = 90 + (tick / 100) * barMaxWidth;
          return (
            <g key={`grid-${tick}`}>
              <line
                x1={x}
                y1={10}
                x2={x}
                y2={chartHeight - 20}
                stroke="var(--border)"
                strokeWidth="1"
                strokeDasharray="3 3"
                opacity={0.5}
              />
              <text
                x={x}
                y={chartHeight - 5}
                textAnchor="middle"
                fill="var(--text-muted)"
                fontSize="11"
              >
                {tick}
              </text>
            </g>
          );
        })}

        {items.map((item, i) => {
          const y = 25 + i * 70;
          const barWidth = (item.value / item.max) * barMaxWidth;
          return (
            <g key={`bar-${i}`}>
              {/* 标签 */}
              <text
                x={80}
                y={y + barHeight / 2 + 5}
                textAnchor="end"
                fill="var(--text)"
                fontSize="14"
                fontWeight="bold"
              >
                {item.label}
              </text>

              {/* 条形背景 */}
              <rect
                x={90}
                y={y}
                width={barMaxWidth}
                height={barHeight}
                rx={6}
                fill="var(--bg-soft)"
              />

              {/* 条形 */}
              <rect
                x={90}
                y={y}
                width={Math.max(barWidth, 4)}
                height={barHeight}
                rx={6}
                fill={item.color}
                className="animate-grow-bar"
                style={{
                  animationDelay: `${i * 0.3}s`,
                }}
              />

              {/* 数值 */}
              <text
                x={90 + Math.max(barWidth, 4) + 8}
                y={y + barHeight / 2 + 5}
                fill="var(--text)"
                fontSize="14"
                fontWeight="bold"
              >
                {i === 0 ? "= 20" : "≈ 94...1"}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

// ===== 主页面 =====
type Phase = "quiz1" | "quiz2" | "summary";

export default function ComparePage() {
  const [phase, setPhase] = useState<Phase>("quiz1");
  const [q1Done, setQ1Done] = useState(false);
  const [q2Done, setQ2Done] = useState(false);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [feedbackFlash, setFeedbackFlash] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const cardRef1 = useRef<HTMLDivElement | null>(null);
  const cardRef2 = useRef<HTMLDivElement | null>(null);

  // 处理选项点击
  const handleChoice = (questionIdx: number, choiceIdx: number) => {
    const question = QUESTIONS[questionIdx];
    const choice = question.choices[choiceIdx];
    const cardRef = questionIdx === 0 ? cardRef1 : cardRef2;

    setSelectedIdx(choiceIdx);

    if (choice.correct) {
      // 正确 - 绿色闪烁
      setFeedbackFlash(true);
      setShowExplanation(true);

      setTimeout(() => {
        if (questionIdx === 0) {
          setQ1Done(true);
          setPhase("quiz2");
        } else {
          setQ2Done(true);
          setPhase("summary");
        }
        setSelectedIdx(null);
        setFeedbackFlash(false);
        setShowExplanation(false);
      }, 1500);
    } else {
      // 错误 - shake 动画
      triggerShake(cardRef.current);
      setTimeout(() => {
        setSelectedIdx(null);
      }, 600);
    }
  };

  return (
    <StepShell topicId="division" stepId="compare">
      <div className="space-y-5">
        {/* 介绍文字 */}
        <div className="text-center">
          <p className="text-sm text-[var(--text-secondary)]">
            两道除法题，一个能口算，一个需要估算，看看有什么不同
          </p>
        </div>

        {/* 第一题: 60 ÷ 3 口算 */}
        {phase === "quiz1" && (
          <section
            ref={cardRef1}
            className={`animate-float-in rounded-[var(--radius)] border-2 p-6 shadow-[var(--shadow-sm)] transition-all duration-300 ${
              feedbackFlash
                ? "border-[var(--signal-success)] bg-[var(--signal-success)]/5"
                : "border-[var(--border)] bg-[var(--bg-card)]"
            }`}
          >
            {/* 题目标签 */}
            <div className="flex items-center gap-2 mb-3">
              <span
                className="flex h-8 w-8 items-center justify-center rounded-lg text-sm font-bold text-white"
                style={{ backgroundColor: "var(--primary)" }}
              >
                1
              </span>
              <span className="text-xs font-medium rounded-full px-2.5 py-0.5 bg-[var(--primary)]/10 text-[var(--primary)]">
                口算题
              </span>
            </div>

            {/* 表达式 */}
            <div className="text-center mb-1">
              <span className="text-3xl font-extrabold text-[var(--text)]">
                60 ÷ 3
              </span>
            </div>
            <p className="text-center text-sm text-[var(--text-secondary)] mb-4">
              {QUESTIONS[0].prompt}
            </p>

            {/* 选项 */}
            <div className="grid grid-cols-2 gap-3">
              {QUESTIONS[0].choices.map((choice, ci) => (
                <button
                  key={`q1-${ci}`}
                  onClick={() => handleChoice(0, ci)}
                  disabled={selectedIdx !== null}
                  className={`
                    rounded-xl border-2 py-3 text-lg font-bold transition-all
                    ${selectedIdx === ci && choice.correct
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)] scale-105"
                      : selectedIdx === ci && !choice.correct
                      ? "opacity-50"
                      : "border-[var(--border)] bg-[var(--bg-card)] text-[var(--text)] hover:border-[var(--primary)] hover:bg-[var(--primary)]/5 cursor-pointer"
                    }
                  `}
                >
                  {choice.label}
                </button>
              ))}
            </div>

            {/* 解释 */}
            {showExplanation && (
              <div className="mt-4 animate-float-in rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3 text-center text-sm text-[var(--text-secondary)]">
                {QUESTIONS[0].explanation}
              </div>
            )}
          </section>
        )}

        {/* 第二题: 283 ÷ 3 估算 */}
        {phase === "quiz2" && (
          <section
            ref={cardRef2}
            className={`animate-float-in rounded-[var(--radius)] border-2 p-6 shadow-[var(--shadow-sm)] transition-all duration-300 ${
              feedbackFlash
                ? "border-[var(--signal-success)] bg-[var(--signal-success)]/5"
                : "border-[var(--border)] bg-[var(--bg-card)]"
            }`}
          >
            {/* 第一题完成标记 */}
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2">
                <span
                  className="flex h-8 w-8 items-center justify-center rounded-lg text-sm font-bold text-white"
                  style={{ backgroundColor: "var(--accent)" }}
                >
                  2
                </span>
                <span className="text-xs font-medium rounded-full px-2.5 py-0.5 bg-[var(--accent)]/10 text-[var(--accent)]">
                  估算题
                </span>
              </div>
              <span className="flex items-center gap-1 text-xs text-[var(--signal-success)]">
                <span className="flex h-5 w-5 items-center justify-center rounded-full bg-[var(--signal-success)] text-white text-[10px]">1</span>
                第 1 题已完成
              </span>
            </div>

            {/* 表达式 */}
            <div className="text-center mb-1">
              <span className="text-3xl font-extrabold text-[var(--text)]">
                283 ÷ 3
              </span>
            </div>
            <p className="text-center text-sm text-[var(--text-secondary)] mb-4">
              {QUESTIONS[1].prompt}
            </p>

            {/* 选项 */}
            <div className="grid grid-cols-2 gap-3">
              {QUESTIONS[1].choices.map((choice, ci) => (
                <button
                  key={`q2-${ci}`}
                  onClick={() => handleChoice(1, ci)}
                  disabled={selectedIdx !== null}
                  className={`
                    rounded-xl border-2 py-3 text-lg font-bold transition-all
                    ${selectedIdx === ci && choice.correct
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)] scale-105"
                      : selectedIdx === ci && !choice.correct
                      ? "opacity-50"
                      : "border-[var(--border)] bg-[var(--bg-card)] text-[var(--text)] hover:border-[var(--accent)] hover:bg-[var(--accent)]/5 cursor-pointer"
                    }
                  `}
                >
                  {choice.label}
                </button>
              ))}
            </div>

            {/* 解释 */}
            {showExplanation && (
              <div className="mt-4 animate-float-in rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3 text-center text-sm text-[var(--text-secondary)]">
                {QUESTIONS[1].explanation}
                <br />
                <span className="text-xs text-[var(--text-muted)] mt-1 inline-block">
                  283 ÷ 3：先算 270 ÷ 3 = 90，再算 13 ÷ 3 = 4...1，合起来约 94 余 1
                </span>
              </div>
            )}
          </section>
        )}

        {/* 对比总结 */}
        {phase === "summary" && (
          <div className="space-y-5">
            {/* 完成卡片 */}
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
              <div className="text-5xl animate-bounce-soft">⚖️</div>
              <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
                {completeMsg}
              </h2>
              <p className="mt-2 text-[var(--text-secondary)]">
                口算直接得出结果，估算先确定大致范围。来看看它们的区别
              </p>
            </div>

            {/* 对比卡片 */}
            <div className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h3 className="text-center font-bold text-[var(--text)] mb-4">
                口算 vs 估算
              </h3>

              <div className="space-y-3">
                {/* 口算卡片 */}
                <div className="rounded-[var(--radius-sm)] border-l-4 p-4" style={{ borderLeftColor: "var(--primary)", backgroundColor: "var(--primary)", opacity: 0.08 }}>
                  <div className="flex items-center gap-2">
                    <span
                      className="flex h-7 w-7 items-center justify-center rounded-lg text-sm font-bold text-white"
                      style={{ backgroundColor: "var(--primary)" }}
                    >
                      1
                    </span>
                    <span className="font-bold text-[var(--text)]">口算题</span>
                  </div>
                  <p className="mt-1 text-sm text-[var(--text)]">
                    <span className="font-bold">60 ÷ 3 = 20</span>
                  </p>
                  <p className="mt-1 text-xs text-[var(--text-secondary)]">
                    整十整百数除以一位数，可以直接口算得出准确答案
                  </p>
                </div>

                {/* 估算卡片 */}
                <div className="rounded-[var(--radius-sm)] border-l-4 p-4" style={{ borderLeftColor: "var(--accent)", backgroundColor: "var(--accent)", opacity: 0.08 }}>
                  <div className="flex items-center gap-2">
                    <span
                      className="flex h-7 w-7 items-center justify-center rounded-lg text-sm font-bold text-white"
                      style={{ backgroundColor: "var(--accent)" }}
                    >
                      2
                    </span>
                    <span className="font-bold text-[var(--text)]">估算题</span>
                  </div>
                  <p className="mt-1 text-sm text-[var(--text)]">
                    <span className="font-bold">283 ÷ 3 ≈ 94...1</span>
                  </p>
                  <p className="mt-1 text-xs text-[var(--text-secondary)]">
                    先估再算：先看接近的整百数，分步进行，最后合起来
                  </p>
                </div>
              </div>
            </div>

            {/* SVG 条形图对比 */}
            <div className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h3 className="text-center font-bold text-[var(--text)] mb-2">
                结果对比
              </h3>
              <p className="text-center text-xs text-[var(--text-muted)] mb-1">
                看看两道题的结果差距有多大
              </p>
              <ComparisonBarChart />
            </div>

            {/* 下一步按钮 */}
            <div className="flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={() => {
                  setPhase("quiz1");
                  setQ1Done(false);
                  setQ2Done(false);
                  setSelectedIdx(null);
                  setFeedbackFlash(false);
                  setShowExplanation(false);
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再做一次
              </button>
              <Link
                href="/learn/division/count"
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：数一数 →
              </Link>
            </div>
          </div>
        )}

        {/* 进度指示 */}
        {phase !== "summary" && (
          <div className="rounded-[var(--radius-sm)] bg-[var(--bg-card)]/60 p-3 text-center text-sm text-[var(--text-secondary)]">
            已完成{" "}
            <span className="font-bold text-[var(--text)]">
              {[q1Done, q2Done].filter(Boolean).length}
            </span>{" "}
            / 2 题
          </div>
        )}
      </div>
    </StepShell>
  );
}
